function isValidTag(name) {
  if (name.length > 100) return false;
  for (let i = 0; i < name.length; i++) {
    if (!(/[a-zA-Z0-9]/.test(name[i])) && !(/-/.test(name[i]))) return false;
  }
  return true;
}

